const { execFile } = require("child_process"); // Use execFile instead of exec
const app = express();

app.get("/whois", (req, res) => {
    const domain = req.query.domain;

    // Validate input: Ensure domain is a string and doesn't contain suspicious characters
    // This is an extra layer of defense (Defense in Depth)
    if (typeof domain !== 'string' || !/^[a-zA-Z0-9.-]+$/.test(domain)) {
        return res.status(400).send("Invalid domain format.");
    }

    // execFile treats arguments as literal strings, preventing shell injection
    execFile("whois", [domain], (err, stdout) => {
        if (err) return res.status(500).send(err.message);
        res.type("text/plain").send(stdout);
    });
});
```

