// serialize.cpp - Improved
void serialize(const Record &r, char *buf, size_t buf_len) {
    // Ensure we don't overflow the destination buffer
    size_t size_to_copy = std::min(sizeof(Record), buf_len);
    std::memcpy(buf, &r, size_to_copy);
